import openai

# Set up OpenAI API credentials
openai.api_key = 'your-api-key'

def generate_response(user_message):
    # Define system instructions
    system_instructions = "You are a customer support assistant. Answer questions helpfully and concisely."
    
    # Concatenate system instructions with user input
    full_prompt = f"System: {system_instructions}\nUser: {user_message}"
    
    try:
        # Send the prompt to GPT model
        response = openai.Completion.create(
            engine="text-davinci-003",
            prompt=full_prompt,
            max_tokens=150,
            n=1,
            stop=None,
            temperature=0.7,
        )
        
        # Extract and return the generated response
        assistant_response = response.choices[0].text.strip()
        return assistant_response
    
    except openai.error.OpenAIError as e:
        return f"An error occurred: {e}"

# Example usage
user_input = "How can I reset my password?"
bot_response = generate_response(user_input)
print(bot_response)